package 'Comment Example' {
  comment /* This is a comment, part of the model, annotating (by default) its owning package. */
  comment Comment1 /* This is a named comment. */
  comment about Automobile /* This is an unnamed comment, annotating an explicitly specified element. */
  part def Automobile;
  alias Car for Automobile {
    comment /* This is a comment annotating its owning element. */
  }
  alias Torque for ISQ::TorqueValue;
}

package 'Package Example' {
  public import ISQ::TorqueValue;
  private import ScalarValues::*;
  part def Automobile;
  alias Car for Automobile;
  alias Torque for ISQ::TorqueValue;
}

package 'Documentation Example' {
  doc /* This is documentation of the owning package. */
  part def Automobile {
    doc Document1 /* This is documentation of Automobile. */
  }
  alias Car for Automobile {
    doc /* This is documentation of the alias. */
  }
  alias Torque for ISQ::TorqueValue;
}

package PartDefinitions {
  private import ScalarValues::*;
  private import ISQ::*;

  part def Vehicle {
    attribute mass : Real;
    attribute dryMass : Real;
    attribute cargoMass : Real;
    part eng : Engine;
    ref part driver : Person;
  }

  attribute def VehicleStatus {
    attribute gearSetting : Integer;
    attribute acceleratorPosition : Real;
  }

  part def Engine {
    attribute displacement : Real;
    attribute horsepower : Real;
  }

  part def Person;
}

package Enumerations {
  private import ScalarValues::*;

  enum def FuelKind {
    gas;
    diesel;
    electric;
  }

  enum def IgnitionOnOff {
    on;
    off;
  }

  attribute def ConditionLevel {
    attribute color : String;
  }

  enum def RiskLevel {
    low;
    medium;
    high;
  }

  part def FuelTank {
    attribute fuelKind : FuelKind;
    attribute capacity : Real;
  }
}

package ItemsAndPorts {
  private import ScalarValues::*;
  private import ISQ::*;

  item def Fuel {
    attribute fuelMass : Real;
  }

  item def FuelCmd {
    attribute throttleLevel : Real;
  }

  item def IgnitionCmd {
    attribute ignitionOnOff : String;
  }

  port def FuelPort {
    out item fuel : Fuel;
  }

  port def FuelCmdPort {
    in item fuelCmd : FuelCmd;
  }

  port def IgnitionCmdPort {
    in item ignitionCmd : IgnitionCmd;
  }

  port def DrivePwrPort {
    out item engineTorque : Real;
  }

  interface def FuelInterface {
    port fuelOutPort : FuelPort;
    port fuelInPort : FuelPort;
  }
}

package Specialization {
  private import ScalarValues::*;

  part def Axle {
    attribute mass : Real;
  }

  part def FrontAxle :> Axle {
    attribute steeringAngle : Real;
  }

  part def RearAxle :> Axle {
    attribute differentialRatio : Real;
  }

  part def Wheel {
    attribute diameter : Real;
    attribute pressure : Real;
  }

  part def Vehicle {
    part frontAxle : FrontAxle;
    part rearAxle : RearAxle;
    part frontWheels : Wheel;
    part rearWheels : Wheel;
  }
}

package PartsTree {
  private import ScalarValues::*;
  private import ISQ::*;

  part def Vehicle;
  part def Engine;
  part def Transmission;
  part def Driveshaft;
  part def FrontAxle;
  part def Axle;
  part def Wheel;
  part def Differential;
  part def StarterMotor;
  part def FuelTank;

  part vehicle : Vehicle {
    part starterMotor : StarterMotor;
    part fuelTank : FuelTank;
    part engine : Engine;
    part transmission : Transmission;
    part driveshaft : Driveshaft;
    part rearAxleAssembly {
      part differential : Differential;
      part rearAxle : Axle;
      part rearWheel1 : Wheel;
      part rearWheel2 : Wheel;
    }
    part frontAxleAssembly {
      part frontAxle : FrontAxle;
      part frontWheels : Wheel;
    }
  }
}

package Connections {
  private import ScalarValues::*;

  port def FuelPort;
  port def ControlPort;
  port def DrivePwrPort;

  part def Engine {
    port fuelInPort : FuelPort;
    port drivePwrPort : DrivePwrPort;
    port controlPort : ControlPort;
  }

  part def FuelTank {
    port fuelOutPort : FuelPort;
  }

  part def Transmission {
    port clutchPort : DrivePwrPort;
    port shaftPort : DrivePwrPort;
  }

  part def Controller {
    port controlPort : ControlPort;
  }

  interface def FuelInterface {
    port fuelOut : FuelPort;
    port fuelIn : FuelPort;
  }

  part vehicle {
    part fuelTank : FuelTank;
    part engine : Engine;
    part transmission : Transmission;
    part controller : Controller;
    connect fuelTank.fuelOutPort to engine.fuelInPort;
    connect engine.drivePwrPort to transmission.clutchPort;
    connect controller.controlPort to engine.controlPort;
  }
}

package AllocationsAndFlows {
  private import ScalarValues::*;

  part def Sensor {
    attribute reading : Real;
  }

  part def Controller {
    attribute command : Real;
  }

  part def Actuator {
    attribute position : Real;
  }

  item def SensorData {
    attribute value : Real;
  }

  item def ControlSignal {
    attribute level : Real;
  }

  part controlSystem {
    part sensor : Sensor;
    part controller : Controller;
    part actuator : Actuator;
    flow from sensor.reading to controller.command;
    flow from controller.command to actuator.position;
    allocate sensor.reading to controller.command;
  }
}

package ActionDefinitions {
  private import ScalarValues::*;

  item def FuelCmd {
    attribute throttleLevel : Real;
  }

  item def Torque;

  action def ProvidePower {
    in item fuelCmd : FuelCmd;
    out attribute wheelTorque : Real;
  }

  action def GenerateTorque {
    in item fuelCmd : FuelCmd;
    out item engineTorque : Torque;
  }

  action def AmplifyTorque {
    in item engineTorque : Torque;
    out item transmissionTorque : Torque;
  }

  action def TransferTorque {
    in item transmissionTorque : Torque;
    out item driveshaftTorque : Torque;
  }

  action def DistributeTorque {
    in item driveshaftTorque : Torque;
    out attribute wheelTorque : Real;
  }
}

package ActionFlow {
  private import ScalarValues::*;

  item def FuelCmd;
  item def Torque;

  action def ProvidePower {
    in item fuelCmd : FuelCmd;
    out attribute wheelTorque : Real;
  }

  action def GenerateTorque {
    in item fuelCmd : FuelCmd;
    out item engineTorque : Torque;
  }

  action def AmplifyTorque {
    in item engineTorque : Torque;
    out item transmissionTorque : Torque;
  }

  action def TransferTorque {
    in item transmissionTorque : Torque;
    out item driveshaftTorque : Torque;
  }

  action def DistributeTorque {
    in item driveshaftTorque : Torque;
    out attribute wheelTorque : Real;
  }

  action providePower : ProvidePower {
    action generateTorque : GenerateTorque;
    action amplifyTorque : AmplifyTorque;
    action transferTorque : TransferTorque;
    action distributeTorque : DistributeTorque;
    flow generateTorque.engineTorque to amplifyTorque.engineTorque;
    flow amplifyTorque.transmissionTorque to transferTorque.transmissionTorque;
    flow transferTorque.driveshaftTorque to distributeTorque.driveshaftTorque;
  }
}

package ActionControlFlow {

  action def GetInVehicle;
  action def DriveToDestination;
  action def GetOutOfVehicle;

  action transportPassenger {
    action driverGetIn : GetInVehicle;
    action passengerGetIn : GetInVehicle;
    action drive : DriveToDestination;
    action driverGetOut : GetOutOfVehicle;
    action passengerGetOut : GetOutOfVehicle;

    first start then fork1;
    fork fork1;
    first fork1 then driverGetIn;
    first fork1 then passengerGetIn;
    first driverGetIn then join1;
    first passengerGetIn then join1;
    join join1;
    first join1 then drive;
    first drive then fork2;
    fork fork2;
    first fork2 then driverGetOut;
    first fork2 then passengerGetOut;
    first driverGetOut then join2;
    first passengerGetOut then join2;
    join join2;
    first join2 then done;
  }
}

package DecisionAndMerge {
  private import ScalarValues::*;

  action def ProcessOrder;
  action def ShipStandard;
  action def ShipExpress;
  action def NotifyCustomer;

  action fulfillOrder {
    action processOrder : ProcessOrder;
    action shipStandard : ShipStandard;
    action shipExpress : ShipExpress;
    action notifyCustomer : NotifyCustomer;

    first start then processOrder;
    first processOrder then decision1;
    decide decision1;
    first decision1 then shipStandard;
    first decision1 then shipExpress;
    first shipStandard then merge1;
    first shipExpress then merge1;
    merge merge1;
    first merge1 then notifyCustomer;
    first notifyCustomer then done;
  }
}

package StateDefinitions {
  private import ScalarValues::*;

  action def WarmUp;
  action def Exercise;
  action def Cooldown;

  state def Exercising {
    entry action warmup : WarmUp;
    do action exercise : Exercise;
    exit action cooldown : Cooldown;
  }

  state def OnOff {
    entry;
    then off;

    state off;
    state on;

    transition off_on
      first off then on;
    transition on_off
      first on then off;
  }
}

package VehicleStates {
  private import ScalarValues::*;

  action def PerformSelfTest;
  action def ProvidePower;
  action def ApplyParkingBrake;
  action def SenseTemperature;

  state def VehicleOperatingStates {
    entry;
    then off;

    state off;
    state starting;
    state on {
      entry action selfTest : PerformSelfTest;
      do action power : ProvidePower;
      exit action brake : ApplyParkingBrake;
    }

    transition off_starting
      first off then starting;
    transition starting_on
      first starting then on;
    transition on_off
      first on then off;
  }

  state def VehicleHealthStates {
    entry;
    then normal;

    state normal;
    state maintenance;
    state degraded;

    transition normal_maintenance
      first normal then maintenance;
    transition normal_degraded
      first normal then degraded;
    transition maintenance_normal
      first maintenance then normal;
    transition degraded_normal
      first degraded then normal;
  }

  state def VehicleStates parallel {
    state operatingStates : VehicleOperatingStates;
    state healthStates : VehicleHealthStates;
  }

  part def Vehicle {
    perform action selfTest : PerformSelfTest;
    perform action providePower : ProvidePower;
    exhibit state vehicleStates : VehicleStates;
  }
}

package RequirementDefinitions {
  private import ScalarValues::*;
  private import ISQ::*;

  requirement def MassRequirement {
    doc /* The actual mass shall be less than the required mass. */
    attribute massRequired : Real;
    attribute massActual : Real;
  }

  requirement def FuelEconomyRequirement {
    doc /* The fuel economy shall meet or exceed the required value. */
    attribute requiredFuelEconomy : Real;
    attribute actualFuelEconomy : Real;
  }

  requirement def PerformanceRequirement {
    doc /* The system shall meet performance targets. */
    attribute targetValue : Real;
    attribute measuredValue : Real;
  }

  constraint def MassConstraint {
    doc /* Mass must not exceed the maximum allowed. */
    attribute maxMass : Real;
    attribute actualMass : Real;
  }
}

package VehicleRequirements {
  private import ScalarValues::*;
  private import ISQ::*;

  part def Vehicle {
    attribute mass : Real;
    attribute dryMass : Real;
    attribute cargoMass : Real;
  }

  requirement def MassRequirement {
    doc /* The actual mass shall be less than the required mass. */
    attribute massRequired : Real;
    attribute massActual : Real;
  }

  requirement def FuelEconomyRequirement {
    doc /* The fuel economy shall meet or exceed the required value. */
    attribute requiredFuelEconomy : Real;
  }

  requirement vehicleSpecification {
    doc /* Top-level vehicle specification requirements. */

    requirement vehicleMassRequirement : MassRequirement {
      doc /* The total mass of the vehicle shall be less than or equal to 2000 kg. */
      attribute massRequired : Real;
      attribute massActual : Real;
    }

    requirement cityFuelEconomy : FuelEconomyRequirement {
      doc /* City fuel economy shall be at least 10 km per litre. */
      attribute requiredFuelEconomy : Real;
    }

    requirement highwayFuelEconomy : FuelEconomyRequirement {
      doc /* Highway fuel economy shall be at least 12.75 km per litre. */
      attribute requiredFuelEconomy : Real;
    }
  }

  part vehicle : Vehicle;
  satisfy vehicleSpecification by vehicle;
}

package UseCases {

  action def GetInVehicle;
  action def DriveToDestination;
  action def GetOutOfVehicle;

  use case def TransportPassenger {
    doc /* The vehicle transports a passenger from origin to destination. */
  }

  use case transportPassenger : TransportPassenger {
    action driverGetIn : GetInVehicle;
    action passengerGetIn : GetInVehicle;
    action drive : DriveToDestination;
    action driverGetOut : GetOutOfVehicle;
    action passengerGetOut : GetOutOfVehicle;

    first start then fork1;
    fork fork1;
    first fork1 then driverGetIn;
    first fork1 then passengerGetIn;
    first driverGetIn then join1;
    first passengerGetIn then join1;
    join join1;
    first join1 then drive;
    first drive then fork2;
    fork fork2;
    first fork2 then driverGetOut;
    first fork2 then passengerGetOut;
    first driverGetOut then join2;
    first passengerGetOut then join2;
    join join2;
    first join2 then done;
  }
}

package AnalysisAndVerification {
  private import ScalarValues::*;
  private import ISQ::*;

  part def Vehicle {
    attribute mass : Real;
  }

  requirement def MassRequirement {
    attribute massRequired : Real;
    attribute massActual : Real;
  }

  requirement vehicleMassReq : MassRequirement {
    doc /* Vehicle mass shall not exceed 2000 kg. */
    attribute massRequired : Real;
    attribute massActual : Real;
  }

  part vehicle : Vehicle;

  analysis case def FuelEconomyAnalysis {
    doc /* Estimate the fuel economy of the vehicle. */
  }

  analysis case fuelEconomyAnalysis : FuelEconomyAnalysis {
    doc /* Compute fuel economy for the given scenario. */
    in attribute scenario : String;
  }

  verification case def MassTest {
    doc /* Verify the vehicle mass meets the requirement. */
  }

  verification case massTest : MassTest {
    doc /* Weigh the vehicle and evaluate pass or fail. */
    action weighVehicle;
    action evaluatePassFail;
    first start then weighVehicle;
    first weighVehicle then evaluatePassFail;
    first evaluatePassFail then done;
  }

  satisfy vehicleMassReq by vehicle;
}

package ViewsAndViewpoints {

  part def SafetyEngineer;

  concern def VehicleSafety {
    doc /* Vehicle must have necessary safety features. */
  }

  viewpoint def SafetyViewpoint {
    doc /* Safety engineering viewpoint. */
  }

  view def TreeView {
    doc /* Renders model elements as a tree diagram. */
  }

  view def PartsTreeView :> TreeView {
    doc /* A tree view filtered to show only parts. */
  }

  rendering def StandardRendering {
    doc /* Default rendering for diagram views. */
  }
}

package MetadataExample {
  private import ScalarValues::*;

  metadata def Approval {
    attribute approved : Boolean;
